namespace sv_a89530eb11cd49f898ec9be11d763178;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var stepNumber = i + 1;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass">
                @if (isCompleted && !isCurrent)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-icon">&#10003;</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <span class="step-content">
                        <span class="step-icon">@stepNumber</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" @bind="FullName" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" @bind="Email" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" @bind="Phone" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <textarea id="address" @bind="Address" @bind:event="oninput" class="form-control" rows="3"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName))
        {
            ErrorMessage = "Full name is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Email))
        {
            ErrorMessage = "Email is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Phone))
        {
            ErrorMessage = "Phone is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Address is required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="work-entry-card">
    <div class="work-entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company *</label>
        <input type="text" value="@Entry.Company" @oninput="e => Update(Entry with { Company = e.Value?.ToString() ?? "" })" class="form-control" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Entry.Title" @oninput="e => Update(Entry with { Title = e.Value?.ToString() ?? "" })" class="form-control" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => Update(Entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" class="form-control" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" @onchange="e => Update(Entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" class="form-control" disabled="@IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleCurrentChanged" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea value="@Entry.Description" @oninput="e => Update(Entry with { Description = e.Value?.ToString() ?? "" })" class="form-control" rows="3"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter, EditorRequired] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.StartDate != default;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void HandleCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        Update(Entry with { EndDate = isCurrent ? null : DateTime.Today });
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       CanRemove="@(Entries.Count > 1)"
                       OnChanged="entry => UpdateEntry(index, entry)"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void UpdateEntry(int index, WorkEntry updated)
    {
        Entries[index] = updated;
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
            if (entry.StartDate == default)
            {
                ErrorMessage = "Each position must have a start date.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="reference-card">
    <div class="reference-header">
        <h4>Reference @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Name *</label>
        <input type="text" value="@Entry.Name" @oninput="e => Update(Entry with { Name = e.Value?.ToString() ?? "" })" class="form-control" />
    </div>

    <div class="form-group">
        <label>Relationship *</label>
        <input type="text" value="@Entry.Relationship" @oninput="e => Update(Entry with { Relationship = e.Value?.ToString() ?? "" })" class="form-control" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Email *</label>
            <input type="email" value="@Entry.Email" @oninput="e => Update(Entry with { Email = e.Value?.ToString() ?? "" })" class="form-control" />
        </div>

        <div class="form-group">
            <label>Phone *</label>
            <input type="tel" value="@Entry.Phone" @oninput="e => Update(Entry with { Phone = e.Value?.ToString() ?? "" })" class="form-control" />
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Reference Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter, EditorRequired] public EventCallback<Reference> OnChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnRemove { get; set; }

    private void Update(Reference updated) => OnChanged.InvokeAsync(updated);
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>References</h2>
    <p class="step-description">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Entry="@References[index]"
                       Index="index"
                       CanRemove="@(References.Count > 2)"
                       OnChanged="entry => UpdateReference(index, entry)"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new Reference("", "", "", ""));
        }
    }

    private void UpdateReference(int index, Reference updated)
    {
        References[index] = updated;
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "Please provide at least 2 references.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync(References);
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Cover Letter</h2>

    <div class="form-group">
        <label for="coverLetter">Write your cover letter</label>
        <textarea id="coverLetter" @bind="CoverLetter" @bind:event="oninput"
                  class="form-control cover-letter-textarea" rows="12" maxlength="2000"></textarea>
        <span class="char-count">@CoverLetter.Length / 2000 characters</span>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<string> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(CoverLetter))
        {
            ErrorMessage = "A cover letter is required.";
            return;
        }

        await OnNext.InvokeAsync(CoverLetter.Trim());
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Review & Submit</h2>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <h3>&#10003; Application Submitted Successfully!</h3>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
            <p>We will review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <section class="review-section">
            <div class="review-section-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Full Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-reference">
                    <strong>@r.Name</strong> (@r.Relationship)
                    <br />@r.Email | @r.Phone
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </section>

        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="error-message" role="alert">@ErrorMessage</div>
        }

        <div class="step-actions">
            <button class="btn btn-outline" @onclick="OnBack">Back</button>
            <button class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = new();
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = new();
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            ApplicationId = await OnSubmit();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

namespace sv_a89530eb11cd49f898ec9be11d763178;

public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<nav class="step-indicator" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var stepIndex = i;
            var stepNumber = i + 1;
            var isCompleted = CompletedSteps.Contains(stepIndex);
            var isCurrent = stepIndex == CurrentStep;
            var cssClass = isCurrent ? "step current" : isCompleted ? "step completed" : "step future";

            <li class="@cssClass">
                @if (isCompleted && !isCurrent)
                {
                    <button class="step-button" @onclick="() => OnStepClicked.InvokeAsync(stepIndex)">
                        <span class="step-icon">&#10003;</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </button>
                }
                else
                {
                    <span class="step-content">
                        <span class="step-icon">@stepNumber</span>
                        <span class="step-label">@StepNames[stepIndex]</span>
                    </span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Personal Information</h2>

    <div class="form-group">
        <label for="fullName">Full Name *</label>
        <input id="fullName" type="text" @bind="FullName" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="email">Email *</label>
        <input id="email" type="email" @bind="Email" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="phone">Phone *</label>
        <input id="phone" type="tel" @bind="Phone" @bind:event="oninput" class="form-control" />
    </div>

    <div class="form-group">
        <label for="address">Address *</label>
        <textarea id="address" @bind="Address" @bind:event="oninput" class="form-control" rows="3"></textarea>
    </div>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
            @(IsValidating ? "Validating..." : "Next")
        </button>
    </div>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public string Address { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private string? ErrorMessage;
    private bool IsValidating;

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (string.IsNullOrWhiteSpace(FullName))
        {
            ErrorMessage = "Full name is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Email))
        {
            ErrorMessage = "Email is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Phone))
        {
            ErrorMessage = "Phone is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(Address))
        {
            ErrorMessage = "Address is required.";
            return;
        }

        IsValidating = true;
        try
        {
            var emailValid = await ValidateEmail(Email);
            if (!emailValid)
            {
                ErrorMessage = "The email address is not valid.";
                return;
            }
        }
        finally
        {
            IsValidating = false;
        }

        await OnNext.InvokeAsync(new PersonalInfo(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim()));
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="work-entry-card">
    <div class="work-entry-header">
        <h4>Position @(Index + 1)</h4>
        @if (CanRemove)
        {
            <button class="btn btn-danger btn-sm" @onclick="() => OnRemove.InvokeAsync()">Remove</button>
        }
    </div>

    <div class="form-group">
        <label>Company *</label>
        <input type="text" value="@Entry.Company" @oninput="e => Update(Entry with { Company = e.Value?.ToString() ?? "" })" class="form-control" />
    </div>

    <div class="form-group">
        <label>Job Title *</label>
        <input type="text" value="@Entry.Title" @oninput="e => Update(Entry with { Title = e.Value?.ToString() ?? "" })" class="form-control" />
    </div>

    <div class="form-row">
        <div class="form-group">
            <label>Start Date *</label>
            <input type="date" value="@Entry.StartDate.ToString("yyyy-MM-dd")" @onchange="e => Update(Entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" class="form-control" />
        </div>

        <div class="form-group">
            <label>End Date</label>
            <input type="date" value="@Entry.EndDate?.ToString("yyyy-MM-dd")" @onchange="e => Update(Entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" class="form-control" disabled="@IsCurrent" />
            <label class="checkbox-label">
                <input type="checkbox" checked="@IsCurrent" @onchange="HandleCurrentChanged" />
                Currently working here
            </label>
        </div>
    </div>

    <div class="form-group">
        <label>Description</label>
        <textarea value="@Entry.Description" @oninput="e => Update(Entry with { Description = e.Value?.ToString() ?? "" })" class="form-control" rows="3"></textarea>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool CanRemove { get; set; }
    [Parameter, EditorRequired] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.StartDate != default;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void HandleCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        Update(Entry with { EndDate = isCurrent ? null : DateTime.Today });
    }
}

@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Work History</h2>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryForm Entry="@Entries[index]"
                       Index="index"
                       CanRemove="@(Entries.Count > 1)"
                       OnChanged="entry => UpdateEntry(index, entry)"
                       OnRemove="() => RemoveEntry(index)" />
    }

    <button class="btn btn-secondary" @onclick="AddEntry">+ Add Another Position</button>

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void UpdateEntry(int index, WorkEntry updated)
    {
        Entries[index] = updated;
    }

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
        {
            Entries.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                ErrorMessage = "Each position must have a company name and job title.";
                return;
            }
            if (entry.StartDate == default)
            {
                ErrorMessage = "Each position must have a start date.";
                return;
            }
        }

        await OnNext.InvokeAsync(Entries);
    }
}

