    [Parameter] public bool CanRemove { get; set; }
    [Parameter, EditorRequired] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null && Entry.StartDate != default;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void HandleCurrentChanged(ChangeEventArgs e)
    {
        var isCurrent = (bool)(e.Value ?? false);
        Update(Entry with { EndDate = isCurrent ? null : DateTime.Today });
    }
}
"}

{"path": "/tmp/sv-a89530eb11cd49f898ec9be11d763178/Components/Pages/Apply/WorkHistoryStep.razor", "file_text": "@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
