{"path": "/tmp/sv-a89530eb11cd49f898ec9be11d763178/Components/Pages/Apply/ReferencesStep.razor", "file_text": "@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>References</h2>
    <p class="step-description">Please provide 2–3 professional references.</p>

    @for (int i = 0; i < References.Count; i++)
    {
        var index = i;
        <ReferenceForm Entry="@References[index]"
                       Index="index"
                       CanRemove="@(References.Count > 2)"
                       OnChanged="entry => UpdateReference(index, entry)"
                       OnRemove="() => RemoveReference(index)" />
    }

    @if (References.Count < 3)
    {
        <button class="btn btn-secondary" @onclick="AddReference">+ Add Reference</button>
    }

    @if (!string.IsNullOrEmpty(ErrorMessage))
    {
        <div class="error-message" role="alert">@ErrorMessage</div>
    }

    <div class="step-actions">
        <button class="btn btn-outline" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private string? ErrorMessage;

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new Reference("", "", "", ""));
        }
    }

    private void UpdateReference(int index, Reference updated)
    {
        References[index] = updated;
    }

    private void RemoveReference(int index)
    {
        if (References.Count > 2)
        {
            References.RemoveAt(index);
        }
    }

    private async Task HandleNext()
    {
        ErrorMessage = null;

        if (References.Count < 2)
        {
            ErrorMessage = "Please provide at least 2 references.";
            return;
        }

        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Relationship)
                || string.IsNullOrWhiteSpace(r.Email) || string.IsNullOrWhiteSpace(r.Phone))
            {
                ErrorMessage = "All reference fields are required.";
                return;
            }
        }

        await OnNext.InvokeAsync(References);
    }
}
"}

