@namespace sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply

<div class="step-panel">
    <h2>Review & Submit</h2>

    @if (IsSubmitted)
    {
        <div class="confirmation">
            <h3>&#10003; Application Submitted Successfully!</h3>
            <p>Your application ID is: <strong>@ApplicationId</strong></p>
            <p>We will review your application and get back to you soon.</p>
        </div>
    }
    else
    {
        <section class="review-section">
            <div class="review-section-header">
                <h3>Personal Information</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(0)">Edit</button>
            </div>
            <dl>
                <dt>Full Name</dt><dd>@Personal.FullName</dd>
                <dt>Email</dt><dd>@Personal.Email</dd>
                <dt>Phone</dt><dd>@Personal.Phone</dd>
                <dt>Address</dt><dd>@Personal.Address</dd>
            </dl>
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>Work History</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(1)">Edit</button>
            </div>
            @foreach (var entry in WorkEntries)
            {
                <div class="review-work-entry">
                    <strong>@entry.Title</strong> at @entry.Company
                    <br />
                    <span class="date-range">
                        @entry.StartDate.ToString("MMM yyyy") –
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </span>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p>@entry.Description</p>
                    }
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>References</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(2)">Edit</button>
            </div>
            @foreach (var r in References)
            {
                <div class="review-reference">
                    <strong>@r.Name</strong> (@r.Relationship)
                    <br />@r.Email | @r.Phone
                </div>
            }
        </section>

        <section class="review-section">
            <div class="review-section-header">
                <h3>Cover Letter</h3>
                <button class="btn-link" @onclick="() => OnEditSection.InvokeAsync(3)">Edit</button>
            </div>
            <p class="cover-letter-preview">@CoverLetter</p>
        </section>

        @if (!string.IsNullOrEmpty(ErrorMessage))
        {
            <div class="error-message" role="alert">@ErrorMessage</div>
        }

        <div class="step-actions">
            <button class="btn btn-outline" @onclick="OnBack">Back</button>
            <button class="btn btn-primary btn-submit" @onclick="HandleSubmit" disabled="@IsSubmitting">
                @(IsSubmitting ? "Submitting..." : "Submit Application")
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = new();
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = new();
    [Parameter, EditorRequired] public string CoverLetter { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditSection { get; set; }
    [Parameter, EditorRequired] public Func<Task<int>> OnSubmit { get; set; } = default!;

    private bool IsSubmitting;
    private bool IsSubmitted;
    private int ApplicationId;
    private string? ErrorMessage;

    private async Task HandleSubmit()
    {
        ErrorMessage = null;
        IsSubmitting = true;

        try
        {
            ApplicationId = await OnSubmit();
            IsSubmitted = true;
        }
        catch (Exception ex)
        {
            ErrorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

