@page "/apply"
@using sv_a89530eb11cd49f898ec9be11d763178.Components.Pages.Apply
@rendermode InteractiveServer
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    <StepIndicator CurrentStep="_currentStep"
                   CompletedSteps="_completedSteps"
                   OnStepClicked="GoToStep" />

    @switch (_currentStep)
    {
        case 0:
            <PersonalInfoStep FullName="@_fullName"
                              Email="@_email"
                              Phone="@_phone"
                              Address="@_address"
                              ValidateEmail="ApplicationService.ValidateEmailAsync"
                              OnNext="HandlePersonalInfoNext" />
            break;

        case 1:
            <WorkHistoryStep Entries="_workEntries"
                             OnNext="HandleWorkHistoryNext"
                             OnBack="GoBack" />
            break;

        case 2:
            <ReferencesStep References="_references"
                            OnNext="HandleReferencesNext"
                            OnBack="GoBack" />
            break;

        case 3:
            <CoverLetterStep CoverLetter="@_coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="GoBack" />
            break;

        case 4:
            <ReviewStep Personal="@_personalInfo!"
                        WorkEntries="_workEntries"
                        References="_references"
                        CoverLetter="@_coverLetter"
                        OnBack="GoBack"
                        OnEditSection="GoToStep"
                        OnSubmit="SubmitApplication" />
            break;
    }
</div>

@code {
    private int _currentStep;
    private HashSet<int> _completedSteps = new();

    // Personal Info state
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";
    private PersonalInfo? _personalInfo;

    // Work History state
    private List<WorkEntry> _workEntries = new() { new("", "", DateTime.Today, null, "") };

    // References state
    private List<Reference> _references = new() { new("", "", "", ""), new("", "", "", "") };

    // Cover Letter state
    private string _coverLetter = "";

    private void HandlePersonalInfoNext(PersonalInfo info)
    {
        _personalInfo = info;
        _fullName = info.FullName;
        _email = info.Email;
        _phone = info.Phone;
        _address = info.Address;
        CompleteAndAdvance(0);
    }

    private void HandleWorkHistoryNext(List<WorkEntry> entries)
    {
        _workEntries = entries;
        CompleteAndAdvance(1);
    }

    private void HandleReferencesNext(List<Reference> references)
    {
        _references = references;
        CompleteAndAdvance(2);
    }

    private void HandleCoverLetterNext(string coverLetter)
    {
        _coverLetter = coverLetter;
        CompleteAndAdvance(3);
    }

    private void CompleteAndAdvance(int step)
    {
        _completedSteps.Add(step);
        _currentStep = step + 1;
    }

    private void GoToStep(int step)
    {
        _currentStep = step;
    }

    private void GoBack()
    {
        if (_currentStep > 0)
            _currentStep--;
    }

    private async Task<int> SubmitApplication()
    {
        var application = new JobApplication(
            _personalInfo!,
            new WorkHistory(_workEntries),
            _references,
            _coverLetter
        );

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

.apply-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem;
}

.apply-container h1 {
    text-align: center;
    margin-bottom: 2rem;
}

/* Step Indicator */
.step-indicator {
    margin-bottom: 2rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: "";
    position: absolute;
    top: 16px;
    left: 10%;
    right: 10%;
    height: 2px;
    background: #e0e0e0;
    z-index: 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    z-index: 1;
    flex: 1;
}

.step-button,
.step-content {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: default;
    padding: 0;
    font: inherit;
}

.step-button {
    cursor: pointer;
}

.step-button:hover .step-icon {
    background: #1565c0;
}

.step-icon {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    font-weight: bold;
    margin-bottom: 0.5rem;
    background: #e0e0e0;
    color: #757575;
}

.step.current .step-icon {
    background: #1976d2;
