.apply-container {
    max-width: 800px;
    margin: 0 auto;
    padding: 2rem;
}

.apply-container h1 {
    text-align: center;
    margin-bottom: 2rem;
}

/* Step Indicator */
.step-indicator {
    margin-bottom: 2rem;
}

.step-list {
    display: flex;
    list-style: none;
    padding: 0;
    margin: 0;
    justify-content: space-between;
    position: relative;
}

.step-list::before {
    content: "";
    position: absolute;
    top: 16px;
    left: 10%;
    right: 10%;
    height: 2px;
    background: #e0e0e0;
    z-index: 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    z-index: 1;
    flex: 1;
}

.step-button,
.step-content {
    display: flex;
    flex-direction: column;
    align-items: center;
    background: none;
    border: none;
    cursor: default;
    padding: 0;
    font: inherit;
}

.step-button {
    cursor: pointer;
}

.step-button:hover .step-icon {
    background: #1565c0;
}

.step-icon {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 0.85rem;
    font-weight: bold;
    margin-bottom: 0.5rem;
    background: #e0e0e0;
    color: #757575;
}

.step.current .step-icon {
    background: #1976d2;
    color: white;
}

.step.completed .step-icon {
    background: #388e3c;
    color: white;
}

.step.future .step-icon {
    background: #e0e0e0;
    color: #9e9e9e;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #757575;
}

.step.current .step-label {
    color: #1976d2;
    font-weight: 600;
}

.step.completed .step-label {
    color: #388e3c;
}

/* Step Panels */
.step-panel {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 2rem;
}

.step-panel h2 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    color: #333;
}

.step-description {
    color: #666;
    margin-bottom: 1rem;
}

/* Forms */
.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.25rem;
    font-weight: 500;
    color: #444;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 1rem;
    box-sizing: border-box;
}

.form-control:focus {
    outline: none;
    border-color: #1976d2;
    box-shadow: 0 0 0 2px rgba(25, 118, 210, 0.2);
}

.form-row {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 1rem;
}

.checkbox-label {
    display: inline-flex !important;
    align-items: center;
    gap: 0.5rem;
    margin-top: 0.5rem;
    font-weight: normal !important;
}

/* Buttons */
.step-actions {
    display: flex;
    justify-content: space-between;
    margin-top: 2rem;
    padding-top: 1rem;
    border-top: 1px solid #e0e0e0;
}

.btn {
    padding: 0.6rem 1.5rem;
    border-radius: 4px;
    font-size: 1rem;
    cursor: pointer;
    border: none;
    font-weight: 500;
}

.btn:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-primary {
    background: #1976d2;
    color: white;
}

.btn-primary:hover:not(:disabled) {
    background: #1565c0;
}

.btn-outline {
    background: transparent;
    border: 1px solid #1976d2;
    color: #1976d2;
